import { ux } from '@oclif/core/ux';
import { hux } from '@heroku/heroku-cli-util';
import { pipelineName, repoName } from './validate.js';
function filter(obj) {
    const ret = {};
    Object.keys(obj)
        .filter((key) => obj[key] !== undefined)
        .forEach((key) => {
        ret[key] = obj[key];
    });
    return ret;
}
export default async function getNameAndRepo(args) {
    const answer = {
        name: '',
        repo: '',
    };
    if (!args.name) {
        const name = await hux.prompt('Pipeline name', {
            required: true,
        });
        const [valid, msg] = pipelineName(name);
        if (valid) {
            answer.name = name;
        }
        else {
            ux.error(msg);
        }
    }
    if (!args.repo) {
        const repo = await hux.prompt('GitHub repository to connect to (e.g. rails/rails)', {
            required: true,
        });
        const [valid, msg] = repoName(repo);
        if (valid) {
            answer.repo = repo;
        }
        else {
            ux.error(msg);
        }
    }
    const reply = Object.assign(filter(answer), filter(args));
    reply.name = reply.name.toLowerCase().replace(/\s/g, '-');
    return reply;
}
